if &DeletarOperacoesFolha = Status_SimNao.Sim &Sql = "delete OperacoesFolha where EmpCod = " + &EmpCod.ToFormattedString() Do 'RodaScript' EndIf
//Insert Operações Crédito &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",1,'Salário Mensal','C','S','S','S',1, 'A')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",2,'Salário Família','C','N','N','N',2, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",3,'Salário Maternidade','C','S','S','S',3, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",4,'Seguro de Vida','C','N','N','N',4, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",5,'Adicional de Insalubridade','C','S','S','S',5, 'F')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",6,'Adicional de Periculosidade','C','S','S','S',6, 'E')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",7,'Adicional Noturno','C','S','S','S',7, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",8,'Abono de natureza salarial','C','S','S','S',8, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",9,'Décimo Terceiro Salário – Adiantamento','C','S','S','S',9, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",10,'Décimo Terceiro Salário – 1ª parcela','C','S','N','N',10, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",11,'Décimo Terceiro Salário – 2ª parcela','C','S','S','S',11, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",12,'Décimo Terceiro Salário – Rescisão','C','S','S','S',12, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",13,'Aviso Prévio Indenizado','C','S','N','N',13, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",14,'Aviso Prévio Trabalhado','C','S','S','S',14, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",15,'Férias Normais','C','S','S','S',15, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",16,'Férias Adicional 1/3','C','S','S','S',16, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",17,'Horas Extras','C','S','S','S',17, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",18,'Participação nos Lucros','C','N','S','N',18, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",19,'Vale-Transporte','C','N','N','N',19, 'G')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",20,'Vale Refeição','C','N','N','N',20, 'H')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",21,'Comissão','C','S','S','S',21, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",22,'Pró-Labore','C','S','S','S',22, 'A')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",23,'Pagamento Diárias','C','S','S','S',1, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",24,'Multa rescisória','C','S','S','S',1, 'X')" //Insert Operações Débito &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",95,'Adiantamento Salarial','D','N','N','N',95, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",96,'Faltas','D','N','N','N',96, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",97,'Contribuição Sindical','D','N','N','N',97, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",98,'I.R.R.F.','D','N','N','N',98, 'X')" &Sql += "Insert into OperacoesFolha (EmpCod,LcfCod,LcfNom,LcfCreDeb,LcfIsFgts,LcfIsIRRF,LcfIsInss,LcfCodImp, LcfVlrPad) values(" + &EmpCod.ToFormattedString() + ",99,'I.N.S.S.','D','N','N','N',99, 'X')" Do 'RodaScript'
//UPDATES &Sql = " update OperacoesFolha set LcfVlrPad = 'A' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 1" &Sql += " update OperacoesFolha set LcfVlrPad = 'F' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 5" &Sql += " update OperacoesFolha set LcfVlrPad = 'E' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 6" &Sql += " update OperacoesFolha set LcfNom = 'Férias Normais' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 15" &Sql += " update OperacoesFolha set LcfNom = 'Férias Adicional 1/3' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 16" &Sql += " update OperacoesFolha set LcfVlrPad = 'G' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 19" &Sql += " update OperacoesFolha set LcfVlrPad = 'H' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 20" &Sql += " update OperacoesFolha set LcfVlrPad = 'A' where EmpCod= "+ &EmpCod.ToFormattedString()+" and LcfCod = 22" Do 'RodaScript'
&Sql = " update OperacoesFolha set LcfVlrPad = 'X' where EmpCod= 1 and (LcfVlrPad is null or LcfVlrPad = '') "
Do 'RodaScript' //TABELA INSS 2016 if &DeletarOperacoesFolha = Status_SimNao.Sim &Sql += "delete INSS where EmpCod = " + &EmpCod.ToFormattedString() Do 'RodaScript' EndIf &Sql += "Insert Into INSS (EmpCod,InssCod,InssVlrIni,InssVlrFin,InssTax) values(" + &EmpCod.ToFormattedString() + ",1,0,1556.94,8)" &Sql += "Insert Into INSS (EmpCod,InssCod,InssVlrIni,InssVlrFin,InssTax) values(" + &EmpCod.ToFormattedString() + ",2,1556.95,2594.92,9)" &Sql += "Insert Into INSS (EmpCod,InssCod,InssVlrIni,InssVlrFin,InssTax) values(" + &EmpCod.ToFormattedString() + ",3,2594.93,5189.82,11)" &Sql += "Insert Into INSS (EmpCod,InssCod,InssVlrIni,InssVlrFin,InssTax) values(" + &EmpCod.ToFormattedString() + ",4,5189.83,10000.00,11)" Do 'RodaScript'
//TABELA IRRF if &DeletarOperacoesFolha = Status_SimNao.Sim &Sql += "DELETE IRRF where EmpCod = " + &EmpCod.ToFormattedString() Do 'RodaScript' EndIf &Sql += "Insert Into IRRF (EmpCod,IrrfCod,IrrfVlrIni,IrrfVlrFin,IrrfTax,IrrfDed,IrrfDedDep) values(" + &EmpCod.ToFormattedString() + ",1,1903.99,2826.65, 7.5,142.80,189.59)" &Sql += "Insert Into IRRF (EmpCod,IrrfCod,IrrfVlrIni,IrrfVlrFin,IrrfTax,IrrfDed,IrrfDedDep) values(" + &EmpCod.ToFormattedString() + ",2,2826.66,3751.05, 15,354.80,189.59)" &Sql += "Insert Into IRRF (EmpCod,IrrfCod,IrrfVlrIni,IrrfVlrFin,IrrfTax,IrrfDed,IrrfDedDep) values(" + &EmpCod.ToFormattedString() + ",3,3751.06,4664.68, 22.5,636.13,189.59)" &Sql += "Insert Into IRRF (EmpCod,IrrfCod,IrrfVlrIni,IrrfVlrFin,IrrfTax,IrrfDed,IrrfDedDep) values(" + &EmpCod.ToFormattedString() + ",4,4664.68,10000.00,27.5,869.36,189.59)" Do 'RodaScript'
//SALARIO FAMILIA if &DeletarOperacoesFolha = Status_SimNao.Sim &Sql += "DELETE SalarioFamilia where EmpCod = " +&EmpCod.ToFormattedString() Do 'RodaScript' EndIf &Sql += "Insert Into SalarioFamilia (EmpCod,SalFamCod,SalFamIni,SalFamFin,SalFamVlr) values(" + &EmpCod.ToFormattedString() + ",1,0,806.80,41.37)" &Sql += "Insert Into SalarioFamilia (EmpCod,SalFamCod,SalFamIni,SalFamFin,SalFamVlr) values(" + &EmpCod.ToFormattedString() + ",2,806.81,1212.64,29.16)" Do 'RodaScript'
Sub 'RodaScript' if &Sql <> '' sql [!&sql!] commit &Sql = '' EndIf EndSub
